import {sessionInfo} from "@acepad/sessions";

// @acepad/logging
const logdirpath="/log/";
const thresh=10000;
let alerted;

export function main(){
  const sh=this;
  const acepad=this.$acepad;
      if (process.env.ACEPAD_LOGGING) {
        acepad.events.on("keyclick",({b})=>{
            if(acepad.getCurrentEditor().nolog)return ;
            //console.log(b,b.classList.contains("guide"));
            addLog(sh,{
              text:b.innerText,
              ...(b.classList.contains("guide")?
                {guide:true}:{})
            });
        });
        acepad.events.on("complete",(e)=>{
          addLog(sh,{
            text:e.text,
            complete:1
            
          });
        });
        acepad.getMainEditor().
        on("changeSession", (e)=>{
          const si=sessionInfo(e.session);
          addLog(sh,{
            name:si.name,
            ...(
              si.file?
              {file:si.file+""}:{})
          });
        });
    
         acepad.getMainEditor().
      container.addEventListener(
        "touchstart",()=>{
          //console.log("touced")
          addLog(sh,{
            touched:1
          });
        });
     
    }

}
export function addLog(sh,data){
    const logdir=sh.resolve(logdirpath);
    if(!logdir.exists())logdir.mkdir();
    const logfile=logdir.rel("keyclick.json");
    let logdata=[];
    try{
        logdata=logfile.obj();    
    }catch(e){}
    data.time=new Date().getTime();
    logdata.push(data);
    logfile.obj(logdata);
    if(logdata.length>=thresh&&!alerted){
        //console.log(logdata.length);
        alert("dumplog");
        alerted=true;
    }
}
